};

// Read the file
const content = readFileSync\(filePath, 'utf8'\);
const lines = content.split\('\\n'\);

const result = [];
let currentLang = null;
let insertCount = 0;

for \(let i = 0; i < lines.length; i++\) {
  const line = lines[i];

  // Detect which language function we're in
  const funcMatch = line.match\(/private fun \(\\w+\)Translations\\\(\\\)/\);
  if \(funcMatch\) {
    currentLang = funcMatch[1];
  }

  // Check if this is a damage_presets line
  if \(line.match\(/^\\s+"damage_presets" to "/\)\) {
    result.push\(line\);

    // Get the indentation from this line
    const indentMatch = line.match\(/^\(\\s+\)"damage_presets"/\);
    const indent = indentMatch ? indentMatch[1] : '        ';

    if \(currentLang && translations[currentLang]\) {
      const trans = translations[currentLang];
      for \(let k = 0; k < keys.length; k++\) {
        const newLine = `${indent}"${keys[k]}" to "${trans[k]}",`;
        result.push\(newLine\);
      }
      insertCount++;
      console.log\(`Inserted translations for: ${currentLang} \(line ${i + 1}\)`\);
    } else {
      console.log\(`WARNING: No translations found for language: ${currentLang}`\);
    }
  } else {
    result.push\(line\);
  }
}

console.log\(''\);
console.log\(`Total language functions processed: ${insertCount}`\);
console.log\(`Total lines before: ${lines.length}`\);
console.log\(`Total lines after: ${result.length}`\);
console.log\(`Lines added: ${result.length - lines.length}`\);

// Write back as UTF-8 \(Node.js writes UTF-8 without BOM by default\)
const outputContent = result.join\('\\n'\);
writeFileSync\(filePath, outputContent, 'utf8'\);

console.log\(''\);
console.log\('File written successfully!'\);
ENDOFSCRIPT)

